sql:
SELECT chart_name, description
FROM charts
WHERE update_date = (
    SELECT MAX(update_date)
    FROM charts
);

SELECT chart_name
FROM charts
WHERE chart_id = 0;

SELECT c.*, s.* 
FROM charts c
INNER JOIN songs s ON c.chart_name = s.title;

SELECT user_profiles.user_name, user_profiles.role, search_queries.query
FROM user_profiles
INNER JOIN search_queries ON user_profiles.user_id = search_queries.user_id;

external_knowledge:
- "musical categories" refers to genres of songs in this context;
- "highest number of entries in the charts" means songs frequently appearing in chart rankings;
- "listing just the top five" indicates only the genres with the highest counts should be mentioned.

sql:
SELECT user_name, department, email
FROM user_profiles
WHERE role = 'analyst';

SELECT user_id, COUNT(DISTINCT collaborator_id) as num_collaborators
FROM collaborations
GROUP BY user_id;

SELECT LN(COUNT(*)) 
FROM charts 
WHERE creation_date > '1963-12-18';

SELECT publisher_name, country 
FROM publishers 
WHERE publisher_id < 5;
